#include<bits/stdc++.h>
using namespace std;
int n,a[255],dp[255][255],ans;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        dp[i][i]=a[i];
        ans=max(ans,a[i]);
    }
    for(int len=2;len<=n;len++)
    {
        for(int l=1,r=len;r<=n;r++,l++)
        {
            for(int k=l;k<r;k++)
            {
                if(dp[l][k]!=dp[k+1][r]||!dp[l][k]) continue;
                dp[l][r]=max(dp[l][r],dp[l][k]+1);
                ans=max(ans,dp[l][r]);
            }
        }
    }
    cout<<ans;
    return 0;
}
